arguments.argument:
if lightningProg=0
{
  image_xscale+=0.2
  image_yscale+=0.2
  if image_xscale>=1 {lightningProg+=1}
}
else if lightningProg=1
{
  lightningTime+=1
  if lightningTime>=30
  {
    lightningProg+=1
  }
}
else if lightningProg=2
{
  image_alpha-=0.2
  if image_alpha<=0 {instance_destroy()}
}

if backAlpha>0 {backAlpha-=0.02}
